def _resolve_dynamic_defaults(
    ctx: Context, params: cabc.Iterable[Parameter]
) -> None:
    """Second-pass resolution for options whose default is a dynamic
    mapping keyed by other options' values. This runs after every
    parameter has been parsed, so it has access to the final value of
